    async def _execute_trade(self, trade: TradeOffer) -> dict:
        """
        Execute the actual item transfer atomically.
        Acquires locks in consistent order to prevent deadlocks.
        """
        # Always lock in sorted order by player_id to prevent deadlocks
        ids = sorted([trade.initiator_id, trade.receiver_id])
        lock1 = self._get_inventory_lock(ids[0])
        lock2 = self._get_inventory_lock(ids[1])

        async with lock1:
            async with lock2:
                initiator = self._players.get(trade.initiator_id)
                receiver = self._players.get(trade.receiver_id)

                if not initiator or not receiver:
                    return {"success": False, "error": "Player not found"}

                # Validate all items still exist and are owned by correct players
                for item_id in trade.initiator_items:
                    if not initiator.owns_item(item_id):
                        return {"success": False, "error": f"Initiator no longer owns item {item_id}"}
                    item = initiator.inventory[item_id]
                    if not item.tradeable:
                        return {"success": False, "error": f"Item {item.name} is not tradeable"}

                for item_id in trade.receiver_items:
                    if not receiver.owns_item(item_id):
                        return {"success": False, "error": f"Receiver no longer owns item {item_id}"}
                    item = receiver.inventory[item_id]
                    if not item.tradeable:
                        return {"success": False, "error": f"Item {item.name} is not tradeable"}

                # Check inventory space
                initiator_net = len(trade.receiver_items) - len(trade.initiator_items)
                receiver_net = len(trade.initiator_items) - len(trade.receiver_items)

                if initiator_net > 0 and not initiator.has_space(initiator_net):
                    return {"success": False, "error": "Initiator doesn't have enough inventory space"}
                if receiver_net > 0 and not receiver.has_space(receiver_net):
                    return {"success": False, "error": "Receiver doesn't have enough inventory space"}

                # Perform the swap atomically
                # Remove items from initiator
                items_from_initiator = {}
                for item_id in trade.initiator_items:
                    items_from_initiator[item_id] = initiator.inventory.pop(item_id)

                # Remove items from receiver
                items_from_receiver = {}
                for item_id in trade.receiver_items:
                    items_from_receiver[item_id] = receiver.inventory.pop(item_id)

                # Add items to receiver from initiator
                for item_id, item in items_from_initiator.items():
                    receiver.inventory[item_id] = item

                # Add items to initiator from receiver
                for item_id, item in items_from_receiver.items():
                    initiator.inventory[item_id] = item

                logger.info(
                    f"Trade {trade.trade_id} completed: "
                    f"{initiator.username} gave {len(trade.initiator_items)} items, "
                    f"received {len(trade.receiver_items)} items"
                )

                return {"success": True}

